var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"흐아아……. 개운하다…….","JPN":"ふああ……すっきり……","ENG":"Ahh... I feel so refreshed...","TWN":"呼哈～～真舒服……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜만에 푹 잤어! 꿈을… 악몽을…… 안 꾼 것 같아.","JPN":"久しぶりにぐっすり寝たよ！　夢を……悪夢を……見てないみたい。","ENG":"I haven’t slept like this in ages! And I... don’t think I had any nightmares too.","TWN":"好久沒睡得這麼沉了！好像…完全……沒有做惡夢。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"어? 나도! 공기도 상쾌한 게…… 벽이 뚫려서 그런 줄 알았는데 악몽을 안 꿨네.","JPN":"え？　私も！　空気もさわやかで……壁に穴があいたからかと思ったんだけど、悪夢を見てないや。","ENG":"Huh? Me too! Even the air feels fresh... I thought it was because of the hole in the wall, but it’s because I didn’t have a nightmare.","TWN":"這麼說來？我也是欸！空氣好清新……我還以為是因為牆被踹破的關係，原來是因為沒做惡夢！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"벼, 벽은 왜 저래?! 진짜 구멍이 뚫렸잖아?","JPN":"か、壁はどうなってるの！？　本当に穴があいてるじゃん！","ENG":"W-what happened to the wall?! There’s really a hole in it!!","TWN":"牆…牆壁怎麼變那樣？！真的破了個大洞欸？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"너희는…… 도로시?","JPN":"あんたたちは……ドロシー？","ENG":"Hey, aren’t you... Dorothy?","TWN":"你們是……桃樂絲？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지나! 정신이 좀 들어?","JPN":"ジナ！　気がついた？","ENG":"Gina! Do you finally recognize me?","TWN":"吉娜！你恢復了嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"도로시! 여긴 왜 또 돌아온 거야! 미쳤어?!","JPN":"ドロシー！　なんで戻ってきたの！　頭おかしくなった！？","ENG":"Dorothy! Why did you come back here? Are you crazy?!","TWN":"桃樂絲！你為什麼又回來這裡！你腦袋壞掉嗎？！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"안 미쳤어! 돌아온 게 아니라 구하러 온 거야.","JPN":"おかしくなってないよ！　戻ったんじゃなくて、助けに来たんだ。","ENG":"Nope! I didn’t just come back. I’m here to rescue you.","TWN":"才沒壞！我是回來救你們的！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"우릴…… 구하러?","JPN":"私たちを……助けに？","ENG":"Rescue... us?","TWN":"回來……救我們？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"응. 네 덕분에 우리가 도망갔었으니까, 이젠 우리가 너흴 도와줄 차례지.","JPN":"うん。君のおかげで逃げられたから、今度は私たちがジナたちを助ける番だ。","ENG":"Yeap. We were able to escape because of you. So now it’s our turn to help you.","TWN":"嗯，因為你我們才能逃離這裡，所以現在換我們回來救你們！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"관리국 정보원이랑 연락해서 보호받았어. 덕분에 너희를 구하러 올 정보도 공유 받았고.","JPN":"管理局の情報員に連絡を取って、保護してもらったんだ。おかげで君たちを助けにくるための情報ももらえたし。","ENG":"We got in contact with an informant from the Administration. Thanks to her, we were able to get intel about your whereabouts.","TWN":"我們和管理局的情報員聯絡上後，受到庇護。她還跟我們分享很多情報，讓我們可以來救你們。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"……넣어둔 핸드폰이 도움이 됐나 보네. 다행이다.","JPN":"……入れておいた携帯、役に立ったんだね。よかった。","ENG":"I guess that smartphone helped you out. Thank goodness.","TWN":"……太好了，看來我放在你口袋裡的手機有發揮作用。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……가루의 힘이 대단하네. 마치 처음 본 사람처럼 굴고 있어.","JPN":"……粉の力、すごいじゃん。まるで今初めて会った人みたいになってる。","ENG":"That powder is really something. They’re acting like they’re seeing us for the first time.","TWN":"……粉末的效果還真厲害，可以把人變得像陌生人一樣。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"기억이 나도 환상이었다고 생각할 거야. 저 애들은 이제야 현실로 돌아온 셈이지.","JPN":"思い出しても幻だったと思うはずだよ。あの子たちはやっと現実に戻ったんだ。","ENG":"Even if they did remember, they would have dismissed it as a hallucination. For them, they’ve just returned to reality.","TWN":"就算有記憶也會以為是幻想吧，他們現在才是真的回到現實。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시. 회포를 푸는 건 좋은데 시간이 많이 흘렀어. 얼른 가야 돼.","JPN":"ドロシーちゃん。積もる話があるのはわかるけど、結構時間が経ったよ。早く行かなきゃ。","ENG":"Dorothy. I know you want to catch up with your friend, but now is not the time. We have to go.","TWN":"桃樂絲，現在時間不多，必須趕快離開，等出去後再敘舊吧。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아참. 그래! 얘들아, 우리랑 같이…… 갈 거지?","JPN":"あっ、そうだよな！　みんな、一緒に……行くよな？","ENG":"Oh, right. Okay! Guys? You’re coming with us... right?","TWN":"對吼！你說的沒錯！大家，和我們一起……走吧？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아직도 여기에 머물 생각이라면…….","JPN":"まさかここに残る気じゃ……","ENG":"You’re still not thinking of...","TWN":"你們該不會還想繼續待在這……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};